from bisect import bisect_left

def lis_length(nums):
    """
    Returns the length of the longest strictly increasing subsequence.
    """
    tails = []
    for num in nums:
        pos = bisect_left(tails, num)
        if pos == len(tails):
            tails.append(num)     # extend LIS
        else:
            tails[pos] = ___________  # replace with smaller tail
    return len(tails)
